import{_ as e,o as s,c as t,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"历史版本 - Bug修复报告","description":"修仙插件 Bug 修复报告（2026-06-23）","frontmatter":{"title":"历史版本 - Bug修复报告","description":"修仙插件 Bug 修复报告（2026-06-23）","outline":[2,3]},"headers":[],"relativePath":"guide/lishibug.md","filePath":"guide/lishibug.md","lastUpdated":null}'),o={name:"guide/lishibug.md"};function i(d,a,r,l,p,c){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="修仙插件-bug-修复报告" tabindex="-1">修仙插件 Bug 修复报告 <a class="header-anchor" href="#修仙插件-bug-修复报告" aria-label="Permalink to &quot;修仙插件 Bug 修复报告&quot;">​</a></h1><blockquote><p>基于暂存更改 (<code>git diff --cached</code>) 分析，共涉及 12 个文件（含 1 个新增文件）。 生成时间：2026-06-23 01:46 UTC+8</p></blockquote><hr><h2 id="一、变更概览" tabindex="-1">一、变更概览 <a class="header-anchor" href="#一、变更概览" aria-label="Permalink to &quot;一、变更概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>变更类型</th><th>风险等级</th></tr></thead><tbody><tr><td>Commands/PlayerCommands.cs</td><td>功能增强 + 代码重构</td><td>低</td></tr><tr><td>Models/RealmEquipmentConfig.cs</td><td>物品ID常量化重构</td><td><strong>中</strong></td></tr><tr><td>Models/Technique.cs</td><td>Bug修复 + ID常量化</td><td>低</td></tr><tr><td>Systems/BossProjectileSystem.cs</td><td>代码清理</td><td>低</td></tr><tr><td>Systems/BreakthroughSystem.cs</td><td>Bug修复</td><td>低</td></tr><tr><td>Systems/Collect.cs</td><td>数据模型重构</td><td>低</td></tr><tr><td>Systems/CultNotify.cs</td><td>功能增强</td><td>低</td></tr><tr><td>Systems/CultivationManager.cs</td><td><strong>核心重构</strong></td><td><strong>高</strong></td></tr><tr><td>Systems/PillSystem.cs</td><td>Bug修复</td><td>低</td></tr><tr><td>Systems/SkillSystem.cs</td><td>代码重构</td><td>低</td></tr><tr><td>Systems/TribulationSystem.cs</td><td>Bug修复</td><td>低</td></tr><tr><td>Utils/CombatIntegration.cs</td><td>功能调整</td><td>低</td></tr></tbody></table><hr><h2 id="二、已修复的-bug-正面变更" tabindex="-1">二、已修复的 Bug（正面变更） <a class="header-anchor" href="#二、已修复的-bug-正面变更" aria-label="Permalink to &quot;二、已修复的 Bug（正面变更）&quot;">​</a></h2><h3 id="bug-1-✅-境界突破后属性不刷新" tabindex="-1">Bug #1 ✅ 境界突破后属性不刷新 <a class="header-anchor" href="#bug-1-✅-境界突破后属性不刷新" aria-label="Permalink to &quot;Bug #1 ✅ 境界突破后属性不刷新&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/BreakthroughSystem.cs</code></p><p><strong>问题</strong>: 突破成功/失败导致境界变化后，玩家的 HP/魔力上限没有立即刷新，需要等到下一次 OnGameUpdate 周期（1秒间隔）。玩家在这 1 秒内可能以旧的血量上限被击杀。</p><p><strong>修复</strong>: 在三处突破逻辑中（失败倒退回退、小境界晋升、大境界晋升）添加了 <code>_mgr.ApplyCultivationStats(player, data)</code>，立即同步属性到 Terraria 客户端。</p><h3 id="bug-2-✅-渡劫死亡检测不完善" tabindex="-1">Bug #2 ✅ 渡劫死亡检测不完善 <a class="header-anchor" href="#bug-2-✅-渡劫死亡检测不完善" aria-label="Permalink to &quot;Bug #2 ✅ 渡劫死亡检测不完善&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/TribulationSystem.cs</code></p><p><strong>问题</strong>: 渡劫期间仅通过 <code>statLife &lt;= 0</code> 判断死亡，但 Terraria 存在帧延迟：死亡动画播放时 <code>statLife</code> 可能尚未归零，但 <code>player.TPlayer.dead</code> 已为 <code>true</code>。导致天雷击杀判定延迟 1-2 帧，玩家可能多挨一雷。</p><p><strong>修复</strong>: 死亡检测改为 <code>player.TPlayer.statLife &lt;= 0 || player.TPlayer.dead</code>。</p><h3 id="bug-3-✅-渡劫失败后-死后复活" tabindex="-1">Bug #3 ✅ 渡劫失败后&quot;死后复活&quot; <a class="header-anchor" href="#bug-3-✅-渡劫失败后-死后复活" aria-label="Permalink to &quot;Bug #3 ✅ 渡劫失败后&quot;死后复活&quot;&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/TribulationSystem.cs</code></p><p><strong>问题</strong>: 渡劫失败时 <code>FailTribulation</code> 强制将生命设为 <code>Math.Max(1, ...)</code> 。如果玩家已被天雷击杀（<code>statLife &lt;= 0</code>），此操作会将死去的玩家生命设回正数，造成&quot;死了又活了&quot;的异常状态。</p><p><strong>修复</strong>: 添加守卫条件 <code>if (player.TPlayer.statLife &gt; 0 &amp;&amp; !player.TPlayer.dead)</code>，只在玩家存活时扣血惩罚。</p><h3 id="bug-4-✅-每-tick-覆写-statlifemax-statmanamax-导致原版生命成长被清零" tabindex="-1">Bug #4 ✅ 每 Tick 覆写 statLifeMax/statManaMax 导致原版生命成长被清零 <a class="header-anchor" href="#bug-4-✅-每-tick-覆写-statlifemax-statmanamax-导致原版生命成长被清零" aria-label="Permalink to &quot;Bug #4 ✅ 每 Tick 覆写 statLifeMax/statManaMax 导致原版生命成长被清零&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/CultivationManager.cs</code>（核心重构）</p><p><strong>问题</strong>: 旧逻辑 <code>ApplyCachedStats</code> 每 tick 写入 <code>tPlayer.statLifeMax = cp.CachedMaxLife</code>（修仙后的绝对值，如 100+500=600）。但 Terraria 的 <code>Player.Update()</code> 会在每 tick 开始前将 <code>statLifeMax2</code> 同步到 <code>statLifeMax</code>。这意味着玩家原版生命水晶(+20×15=300)、生命果(+5×20=100) 提供的上限会被每 tick 覆盖为固定值 600，原版成长完全失效。</p><p>旧代码流：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每 tick: statLifeMax = 600 (修仙绝对值)</span></span>
<span class="line"><span>         statLifeMax2 = 600</span></span>
<span class="line"><span>下一 tick: Player.Update() 把 statLifeMax2 写回 statLifeMax</span></span>
<span class="line"><span>           再被写成 600  → 生命水晶加成永久丢失</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>修复</strong>: 重构为&quot;加成追踪&quot;模式：</p><ul><li><code>CachedLifeBonus</code> / <code>CachedManaBonus</code> 只存修仙提供的<strong>增量</strong></li><li><code>AppliedLifeBonus</code> / <code>AppliedManaBonus</code> 记录上次已写入的数值</li><li><code>ApplyMaxStatBonuses()</code> 通过 <code>vanilla = 当前 statLifeMax - 上次写入的加成</code> 反推原版基础值，再加新加成</li><li>只在登录、突破、重载配置时写入 <code>statLifeMax</code>/<code>statManaMax</code></li><li>每 tick 只写 <code>statDefense</code> 和 <code>moveSpeed</code>（动态属性）</li></ul><h3 id="bug-5-✅-丹药回血-回蓝上限使用错误的字段" tabindex="-1">Bug #5 ✅ 丹药回血/回蓝上限使用错误的字段 <a class="header-anchor" href="#bug-5-✅-丹药回血-回蓝上限使用错误的字段" aria-label="Permalink to &quot;Bug #5 ✅ 丹药回血/回蓝上限使用错误的字段&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/PillSystem.cs</code></p><p><strong>问题</strong>: 丹药回血使用 <code>statLifeMax</code> 作为上限，但在修仙加成场景下，<code>statLifeMax2</code> 可能比 <code>statLifeMax</code> 更大（用于 UI 显示）。使用较小值导致丹药无法回满。</p><p><strong>修复</strong>: 使用 <code>Math.Max(statLifeMax, statLifeMax2)</code> 和 <code>Math.Max(statManaMax, statManaMax2)</code>。</p><h3 id="bug-6-✅-生命恢复上限使用错误字段" tabindex="-1">Bug #6 ✅ 生命恢复上限使用错误字段 <a class="header-anchor" href="#bug-6-✅-生命恢复上限使用错误字段" aria-label="Permalink to &quot;Bug #6 ✅ 生命恢复上限使用错误字段&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/CultivationManager.cs</code></p><p><strong>问题</strong>: 生命恢复回血使用 <code>statLifeMax</code> 作为上限，导致带修仙加成的玩家回血被过早截断。</p><p><strong>修复</strong>: 改为 <code>tPlayer.statLifeMax2</code>。</p><h3 id="bug-7-✅-非渡劫死亡后-justfailedtribulation-标志未清除" tabindex="-1">Bug #7 ✅ 非渡劫死亡后 JustFailedTribulation 标志未清除 <a class="header-anchor" href="#bug-7-✅-非渡劫死亡后-justfailedtribulation-标志未清除" aria-label="Permalink to &quot;Bug #7 ✅ 非渡劫死亡后 JustFailedTribulation 标志未清除&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/CultivationManager.cs</code></p><p><strong>问题</strong>: 渡劫失败时设置 <code>JustFailedTribulation = true</code>，但如果玩家在非渡劫状态下死亡，该标志不会被重置，导致下次突破判定异常。</p><p><strong>修复</strong>: 玩家死亡时，若非渡劫状态，设置 <code>data.JustFailedTribulation = false</code>。</p><h3 id="bug-8-✅-凡人境界功法学习判定问题" tabindex="-1">Bug #8 ✅ 凡人境界功法学习判定问题 <a class="header-anchor" href="#bug-8-✅-凡人境界功法学习判定问题" aria-label="Permalink to &quot;Bug #8 ✅ 凡人境界功法学习判定问题&quot;">​</a></h3><p><strong>文件</strong>: <code>Models/Technique.cs</code> + <code>Systems/SkillSystem.cs</code></p><p><strong>问题</strong>: 旧的 <code>GetLearnable</code> 判定 <code>t.RequiredSubLevel &lt;= subLevel</code> 在 <code>tier == RealmTier.Mortal</code> 和 <code>t.RequiredRealm == RealmTier.Mortal</code> 且 <code>subLevel == 0</code> 时意外通过（0 &lt;= 0），但逻辑不够清晰。</p><p><strong>修复</strong>: 抽取 <code>MeetsRequirement()</code> 方法，明确处理凡人境界（<code>tier &gt; Mortal ? Math.Max(1, subLevel) : subLevel</code>），统一供 <code>GetLearnable</code> 和 <code>SkillSystem</code> 使用。</p><h3 id="bug-9-✅-buff-projectile-硬编码-id-迁移为命名常量" tabindex="-1">Bug #9 ✅ Buff/Projectile 硬编码 ID 迁移为命名常量 <a class="header-anchor" href="#bug-9-✅-buff-projectile-硬编码-id-迁移为命名常量" aria-label="Permalink to &quot;Bug #9 ✅ Buff/Projectile 硬编码 ID 迁移为命名常量&quot;">​</a></h3><p><strong>文件</strong>: <code>Models/Technique.cs</code> + <code>Systems/BossProjectileSystem.cs</code> + <code>Models/RealmEquipmentConfig.cs</code></p><p><strong>问题</strong>: 大量魔法数字（如 <code>BuffId = 36</code>、<code>ProjectileId = 272</code>、<code>R(65, desc: &quot;星怒&quot;)</code>）难以阅读和维护。</p><p><strong>修复</strong>: 添加 <code>MigrateKnownBuffIds()</code> 和 <code>MigrateKnownProjectileIds()</code> 进行存量数据迁移，新配置统一使用 <code>BuffID.XXX</code> / <code>ProjectileID.XXX</code> / <code>ItemID.XXX</code> 命名常量。</p><hr><h2 id="三、潜在风险与需验证项" tabindex="-1">三、潜在风险与需验证项 <a class="header-anchor" href="#三、潜在风险与需验证项" aria-label="Permalink to &quot;三、潜在风险与需验证项&quot;">​</a></h2><h3 id="风险-1-⚠️-渡劫-境界-metal-奖励物品可能变更" tabindex="-1">风险 #1 ⚠️ &quot;渡劫&quot;境界 Metal 奖励物品可能变更 <a class="header-anchor" href="#风险-1-⚠️-渡劫-境界-metal-奖励物品可能变更" aria-label="Permalink to &quot;风险 #1 ⚠️ &quot;渡劫&quot;境界 Metal 奖励物品可能变更&quot;">​</a></h3><p><strong>文件</strong>: <code>Models/RealmEquipmentConfig.cs</code><strong>位置</strong>: &quot;渡劫&quot; (Tribulation) → rewards → metal</p><p><strong>变更</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原: R(3013, desc: &quot;勇士徽章&quot;)</span></span>
<span class="line"><span>新: R(ItemID.WarriorEmblem, desc: &quot;勇士徽章&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>分析</strong>: 在&quot;金丹&quot;配置中，ID 3013 对应 <code>ItemID.AvengerEmblem</code>（复仇者徽章），ID 2998 对应 <code>ItemID.WarriorEmblem</code>（战士徽章）。原&quot;渡劫&quot; metal 使用了 ID 3013 但描述为&quot;勇士徽章&quot;（即战士徽章），存在 ID 与描述不匹配的原始 Bug。本次重构根据描述匹配到了 <code>ItemID.WarriorEmblem</code>，可能导致实际发放物品从复仇者徽章变为战士徽章。</p><p><strong>建议</strong>: 确认设计意图——&quot;渡劫&quot; metal 应该发放战士徽章还是复仇者徽章？如果是战士徽章，则本次修复了原 Bug；如果是复仇者徽章，则需改为 <code>R(ItemID.AvengerEmblem, desc: &quot;复仇者徽章&quot;)</code>。</p><h3 id="风险-2-⚠️-炼气-境界-heavenly-奖励物品id修复" tabindex="-1">风险 #2 ⚠️ &quot;炼气&quot;境界 Heavenly 奖励物品ID修复 <a class="header-anchor" href="#风险-2-⚠️-炼气-境界-heavenly-奖励物品id修复" aria-label="Permalink to &quot;风险 #2 ⚠️ &quot;炼气&quot;境界 Heavenly 奖励物品ID修复&quot;">​</a></h3><p><strong>文件</strong>: <code>Models/RealmEquipmentConfig.cs</code><strong>位置</strong>: &quot;炼气&quot; (QiCondensation) → rewards → heavenly</p><p><strong>变更</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原: R(50, desc: &quot;云瓶&quot;)</span></span>
<span class="line"><span>新: R(ItemID.CloudinaBottle, desc: &quot;云瓶&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>分析</strong>: 原代码中 ID 50 是 <code>MagicMissile</code>（魔法导弹），描述&quot;云瓶&quot;（Cloud in a Bottle）应为 ID 53。<code>ItemID.CloudinaBottle</code> 正确映射到 Cloud in a Bottle。这是原始 Bug 的修复，但需确认 <code>ItemID.CloudinaBottle</code> 在目标 Terraria 版本中是否确实存在且指向正确 ID。</p><h3 id="风险-3-⚠️-大乘-境界-common-奖励碎片数量变更" tabindex="-1">风险 #3 ⚠️ &quot;大乘&quot;境界 Common 奖励碎片数量变更 <a class="header-anchor" href="#风险-3-⚠️-大乘-境界-common-奖励碎片数量变更" aria-label="Permalink to &quot;风险 #3 ⚠️ &quot;大乘&quot;境界 Common 奖励碎片数量变更&quot;">​</a></h3><p><strong>文件</strong>: <code>Models/RealmEquipmentConfig.cs</code><strong>位置</strong>: &quot;大乘&quot; (GreatVehicle) → common</p><p><strong>变更</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原: R(3601, 10, desc: &quot;天界柱碎片&quot;)           → 总计 10 个碎片</span></span>
<span class="line"><span>新: R(ItemID.FragmentSolar, 10, ...)            → 日耀碎片 ×10</span></span>
<span class="line"><span>    R(ItemID.FragmentVortex, 10, ...)           → 星旋碎片 ×10</span></span>
<span class="line"><span>    R(ItemID.FragmentNebula, 10, ...)           → 星云碎片 ×10</span></span>
<span class="line"><span>    R(ItemID.FragmentStardust, 10, ...)         → 星尘碎片 ×10</span></span>
<span class="line"><span>                                                总计 40 个碎片（4 种各 10 个）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>分析</strong>: 原代码仅发放 10 个 ID 3601 的物品（单一类型），新代码发放 4 种碎片各 10 个共 40 个。如果原 ID 3601 是某种通用碎片或等价物，这可能是重大平衡变更。</p><p><strong>建议</strong>: 确认 ID 3601 对应什么物品，以及 4 种碎片各 10 个是否为设计意图。</p><h3 id="风险-4-⚠️-功法-灵气弹-所需小境界从-1-改为-0" tabindex="-1">风险 #4 ⚠️ 功法&quot;灵气弹&quot;所需小境界从 1 改为 0 <a class="header-anchor" href="#风险-4-⚠️-功法-灵气弹-所需小境界从-1-改为-0" aria-label="Permalink to &quot;风险 #4 ⚠️ 功法&quot;灵气弹&quot;所需小境界从 1 改为 0&quot;">​</a></h3><p><strong>文件</strong>: <code>Models/Technique.cs</code></p><p><strong>变更</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原: Id = 1, Name = &quot;灵气弹&quot;, RequiredRealm = RealmTier.QiCondensation, RequiredSubLevel = 1</span></span>
<span class="line"><span>新: Id = 1, Name = &quot;灵气弹&quot;, RequiredRealm = RealmTier.QiCondensation, RequiredSubLevel = 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>分析</strong>: 新玩家初始 <code>SubLevel = 0</code>，旧逻辑到 <code>SubLevel = 1</code> 才能学习第一个技能，现在变为 SubLevel ≥ 0 即可。这是否为设计意图？配合新的 <code>MeetsRequirement</code> 逻辑（凡人境界下 <code>subLevel</code> 不作 <code>Max(1, ...)</code> 处理），可能改变了新手引导流程。</p><h3 id="风险-5-⚠️-聊天颜色全部变为白色" tabindex="-1">风险 #5 ⚠️ 聊天颜色全部变为白色 <a class="header-anchor" href="#风险-5-⚠️-聊天颜色全部变为白色" aria-label="Permalink to &quot;风险 #5 ⚠️ 聊天颜色全部变为白色&quot;">​</a></h3><p><strong>文件</strong>: <code>Utils/CombatIntegration.cs</code></p><p><strong>变更</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原: var color = GetRealmChatColor(data.RealmTier);</span></span>
<span class="line"><span>    TShock.Utils.Broadcast(final, color.R, color.G, color.B);</span></span>
<span class="line"><span>新: TShock.Utils.Broadcast(final, 255, 255, 255);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>分析</strong>: 删除了 <code>GetRealmChatColor()</code> 方法，聊天消息不再按境界着色，改为全服白色广播。境界颜色信息已移入 <code>{Realm}</code> 占位符内（通过 <code>CultNotify.GetSpiritRootColor</code> 上色），这意味着消息本身的颜色失去了层次感。</p><p><strong>建议</strong>: 确认是否为设计意图——可能为了避免 Chat Tag 和 Broadcast Color 双重着色导致的颜色叠加问题。</p><h3 id="风险-6-⚠️-applymaxstatbonuses-中-statlifemax2-仅上调不下调" tabindex="-1">风险 #6 ⚠️ <code>ApplyMaxStatBonuses</code> 中 <code>statLifeMax2</code> 仅上调不下调 <a class="header-anchor" href="#风险-6-⚠️-applymaxstatbonuses-中-statlifemax2-仅上调不下调" aria-label="Permalink to &quot;风险 #6 ⚠️ \`ApplyMaxStatBonuses\` 中 \`statLifeMax2\` 仅上调不下调&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/CultivationManager.cs</code></p><p><strong>代码</strong>:</p><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (tPlayer.statLifeMax2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> desiredLifeMax)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    tPlayer.statLifeMax2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> desiredLifeMax;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>分析</strong>: 当修仙加成减少时（如突破失败降阶），<code>desiredLifeMax</code> 可能小于当前 <code>statLifeMax2</code>，但此逻辑不会下调 <code>statLifeMax2</code>。这可能导致 UI 显示的血量上限大于实际最大值 <code>statLifeMax</code>。不过 <code>statLifeMax2</code> 的语义是&quot;历史最大生命值&quot;，不下调可能符合 Terraria 原版行为。</p><h3 id="风险-7-⚠️-healing-丹药使用-math-max-statlifemax-statlifemax2-可能在边界情况下出错" tabindex="-1">风险 #7 ⚠️ <code>Healing</code> 丹药使用 <code>Math.Max(statLifeMax, statLifeMax2)</code> 可能在边界情况下出错 <a class="header-anchor" href="#风险-7-⚠️-healing-丹药使用-math-max-statlifemax-statlifemax2-可能在边界情况下出错" aria-label="Permalink to &quot;风险 #7 ⚠️ \`Healing\` 丹药使用 \`Math.Max(statLifeMax, statLifeMax2)\` 可能在边界情况下出错&quot;">​</a></h3><p><strong>文件</strong>: <code>Systems/PillSystem.cs</code></p><p><strong>代码</strong>:</p><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> effectiveMaxLife</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Math.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Max</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(player.TPlayer.statLifeMax, player.TPlayer.statLifeMax2);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>分析</strong>: 如果 <code>statLifeMax2</code> 由于某种原因包含了过期的高值（见风险#6），丹药可能回血超过实际允许的上限，然后被 Terraria 自身的 <code>statLife &gt; statLifeMax2</code> 检查截断。这在当前逻辑下可能正确，但如果有其他插件修改这些字段，行为不可预测。</p><hr><h2 id="四、架构变更说明" tabindex="-1">四、架构变更说明 <a class="header-anchor" href="#四、架构变更说明" aria-label="Permalink to &quot;四、架构变更说明&quot;">​</a></h2><h3 id="_4-1-属性系统重构-本次变更核心" tabindex="-1">4.1 属性系统重构（本次变更核心） <a class="header-anchor" href="#_4-1-属性系统重构-本次变更核心" aria-label="Permalink to &quot;4.1 属性系统重构（本次变更核心）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>旧架构:</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 每 Tick: statLifeMax = 100 + 修仙加成       │</span></span>
<span class="line"><span>│          statManaMax = 20 + 修仙加成         │</span></span>
<span class="line"><span>│          → 原版生命水晶/魔力水晶加成每 tick 被覆写 │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>新架构:</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 事件触发(登录/突破/重载):                    │</span></span>
<span class="line"><span>│   ① vanillaLife = statLifeMax - 上次修仙加成  │</span></span>
<span class="line"><span>│   ② statLifeMax = vanillaLife + 本次修仙加成  │</span></span>
<span class="line"><span>│   ③ 记录 AppliedLifeBonus                     │</span></span>
<span class="line"><span>│                                              │</span></span>
<span class="line"><span>│ 每 Tick: statDefense += 修仙防御              │</span></span>
<span class="line"><span>│          moveSpeed *= 修仙速度倍率             │</span></span>
<span class="line"><span>│          → statLifeMax/statManaMax 不被覆写   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h3 id="_4-2-境界显示渐变增强" tabindex="-1">4.2 境界显示渐变增强 <a class="header-anchor" href="#_4-2-境界显示渐变增强" aria-label="Permalink to &quot;4.2 境界显示渐变增强&quot;">​</a></h3><ul><li>新增 <code>CultNotify.FormatRealmGradient()</code> 系列方法</li><li>渐变色从灵根颜色过渡到境界颜色</li><li>聊天占位符 <code>{Realm}</code> / <code>[{Realm}]</code> 也使用灵根颜色上色</li><li><code>GetSpiritRootColor()</code> 定义了 6 种灵根对应的颜色</li></ul><hr><h2 id="五、测试建议" tabindex="-1">五、测试建议 <a class="header-anchor" href="#五、测试建议" aria-label="Permalink to &quot;五、测试建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优先级</th><th>测试场景</th><th>关注点</th></tr></thead><tbody><tr><td>P0</td><td>新玩家使用生命水晶/生命果后突破境界</td><td>生命上限是否正确叠加（水晶+修仙），不应被覆盖</td></tr><tr><td>P0</td><td>渡劫期间被天雷击杀</td><td>不应出现&quot;死了又复活&quot;的异常</td></tr><tr><td>P0</td><td>连续突破失败 2 次触发降阶</td><td>属性是否立即更新</td></tr><tr><td>P1</td><td>服用回血丹药</td><td>是否能回到正确的满血值</td></tr><tr><td>P1</td><td>学习&quot;灵气弹&quot;（SubLevel=0）</td><td>新玩家是否能立即学习</td></tr><tr><td>P1</td><td>&quot;渡劫&quot; metal 奖励物品确认</td><td>发放的是战士徽章还是复仇者徽章</td></tr><tr><td>P2</td><td>聊天消息显示效果</td><td>境界颜色是否正确，消息可读性</td></tr><tr><td>P2</td><td>配置热重载 (<code>/reload</code>)</td><td>所有在线玩家属性是否刷新</td></tr><tr><td>P2</td><td>非渡劫状态死亡</td><td><code>JustFailedTribulation</code> 是否被正确清除</td></tr></tbody></table><hr><h2 id="六、总结" tabindex="-1">六、总结 <a class="header-anchor" href="#六、总结" aria-label="Permalink to &quot;六、总结&quot;">​</a></h2><p>本次暂存更改包含 <strong>9 个明确的 Bug 修复</strong>（其中属性系统重构是最核心的修复，解决了原版生命成长被清零的严重问题），以及多项代码质量改进（硬编码 ID 迁移为命名常量）。同时存在 <strong>3 个需要确认的潜在数据变更</strong>（奖励物品ID变化、碎片数量变化、技能门槛变化）和 <strong>4 个需要验证的边界条件</strong>。建议在合并前重点验证 P0 级别的测试场景。</p>`,98)])])}const g=e(o,[["render",i]]);export{h as __pageData,g as default};
